INSERT INTO locations ("slug", "name", "summary", "description", "website", "phone", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug", "subcategory_slug") VALUES ('la-jolla-cove', 'La Jolla Cove', 'Picturesque cove beach with clear waters, sea lions, and stunning coastal views', 'La Jolla Cove is a small, picturesque cove and beach in La Jolla, San Diego. Known for its crystal-clear waters, abundant sea life, and dramatic coastal scenery. The area is perfect for swimming, snorkeling, and observing sea lions and seals in their natural habitat. The surrounding cliffs and coves offer excellent photo opportunities.', 'https://www.sandiego.gov/park-and-recreation/parks/beaches', '(858) 459-2555', '1100 Coast Blvd, La Jolla, CA 92037', 'San Diego', 'San Diego', '92037', ST_GeomFromText('SRID=4326;POINT(-117.2719 32.8509)'), true, 4.7, 8923, ARRAY['https://images.unsplash.com/photo-1579605071242-c6a66f5484d4?w=800'], ARRAY['beach', 'snorkeling', 'sea-lions', 'photography', 'family-friendly', 'swimming'], ARRAY['parking', 'restrooms', 'showers', 'lifeguards', 'picnic areas'], false, false, true, '{"beach":"24/7","parking":"Varies, typically 8:00-20:00"}'::jsonb, ARRAY['spring', 'summer', 'fall'], 'parks', 'beaches');
