INSERT INTO locations ("slug", "name", "summary", "description", "website", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug", "subcategory_slug") VALUES ('mission-beach', 'Mission Beach', 'Vibrant 2-mile beach boardwalk with Belmont Park amusement park, surfing, and beach volleyball', 'Mission Beach is a lively 2-mile stretch of sand connecting San Diego Bay to the Pacific Ocean. The beach features a bustling boardwalk perfect for walking, biking, and skating, with Belmont Park amusement park featuring the historic Giant Dipper roller coaster. The area is popular for swimming, surfing, beach volleyball, and people-watching.', 'https://www.sandiego.gov/park-and-recreation/parks/mission-beach', 'Mission Beach, San Diego, CA 92109', 'San Diego', 'San Diego', '92109', ST_GeomFromText('SRID=4326;POINT(-117.2515 32.7725)'), true, 4.6, 8950, ARRAY['https://images.unsplash.com/photo-1505228395891-9a51e7e86bf6?w=800'], ARRAY['boardwalk', 'surfing', 'beach-volleyball', 'family-friendly', 'amusement-park', 'biking', 'skating'], ARRAY['parking', 'restrooms', 'showers', 'lifeguards', 'restaurants', 'shops', 'rentals'], false, false, true, '{"beach":"24/7","boardwalk":"24/7","belmont_park":"11:00-20:00 (seasonal)"}'::jsonb, ARRAY['spring', 'summer', 'fall'], 'parks', 'beaches');
