INSERT INTO locations ("slug", "name", "summary", "description", "website", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug", "subcategory_slug") VALUES ('pacific-beach', 'Pacific Beach', 'Energetic beach town atmosphere with surfing, beach bars, and vibrant nightlife', 'Pacific Beach is a youthful, energetic beach community known for its wide sandy beaches, excellent surfing conditions, and lively social scene. The area features a bustling boardfront with numerous bars, restaurants, and shops. PB attracts a younger crowd and is famous for its beach volleyball, surfing culture, and vibrant nightlife.', 'https://www.pacificbeach.org/', 'Pacific Beach, San Diego, CA 92109', 'San Diego', 'San Diego', '92109', ST_GeomFromText('SRID=4326;POINT(-117.2556 32.7958)'), true, 4.5, 10230, ARRAY['https://images.unsplash.com/photo-1579532582997-4b9c3c4a6a4b?w=800'], ARRAY['surfing', 'nightlife', 'beach-bars', 'young-crowd', 'volleyball', 'social-scene', 'boardfront'], ARRAY['parking', 'restrooms', 'showers', 'lifeguards', 'restaurants', 'bars', 'surf-shops'], false, false, true, '{"beach":"24/7","boardfront":"24/7","establishments":"Varies"}'::jsonb, ARRAY['spring', 'summer', 'fall'], 'parks', 'beaches');
