INSERT INTO locations ("slug", "name", "summary", "description", "website", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug", "subcategory_slug") VALUES ('coronado-beach', 'Coronado Beach', 'Wide, sparkling sand beach with gentle waves and family-friendly atmosphere near Hotel del Coronado', 'Coronado Beach is renowned for its wide, sparkling golden sand and gentle waves, making it perfect for families and swimming. The beach stretches for miles with the iconic Hotel del Coronado as a backdrop. The flat terrain and calm waters make it ideal for children, while the expansive space accommodates beach volleyball, sunbathing, and long walks.', 'https://www.coronadovisitorcenter.com/beaches', 'Coronado Beach, Coronado, CA 92118', 'Coronado', 'San Diego', '92118', ST_GeomFromText('SRID=4326;POINT(-117.1832 32.6848)'), true, 4.8, 12450, ARRAY['https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800'], ARRAY['family-friendly', 'gentle-waves', 'wide-sand', 'hotel-del-coronado', 'swimming', 'romantic', 'fire-pits'], ARRAY['parking', 'restrooms', 'showers', 'lifeguards', 'picnic areas', 'fire-pits', 'beach-wheelchairs'], false, false, true, '{"beach":"24/7","facilities":"6:00-22:00"}'::jsonb, ARRAY['spring', 'summer', 'fall', 'winter'], 'parks', 'beaches');
