INSERT INTO locations ("slug", "name", "summary", "description", "website", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug", "subcategory_slug") VALUES ('ocean-beach', 'Ocean Beach', 'Laid-back beach town with dog-friendly areas, fishing pier, and vintage surf culture', 'Ocean Beach (OB) embodies Southern California''s relaxed beach culture with a bohemian, eclectic vibe. The beach features a long fishing pier, dog-friendly areas, and excellent surf breaks. The community is known for its vintage shops, casual restaurants, and friendly locals. OB offers both beach and bay access, with the Ocean Beach Pier being the longest concrete pier on the West Coast.', 'https://www.oboceanc.org/', 'Ocean Beach, San Diego, CA 92107', 'San Diego', 'San Diego', '92107', ST_GeomFromText('SRID=4326;POINT(-117.2528 32.7522)'), true, 4.6, 9870, ARRAY['https://images.unsplash.com/photo-1505142468610-359e7d316be0?w=800'], ARRAY['dog-friendly', 'fishing-pier', 'surfing', 'bohemian', 'laid-back', 'vintage-culture', 'bay-access'], ARRAY['parking', 'restrooms', 'showers', 'lifeguards', 'fishing-pier', 'dog-park', 'volleyball-courts'], false, false, true, '{"beach":"24/7","pier":"24/7","dog-beach":"24/7"}'::jsonb, ARRAY['spring', 'summer', 'fall', 'winter'], 'parks', 'beaches');
