INSERT INTO locations ("slug", "name", "summary", "description", "website", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug", "subcategory_slug") VALUES ('imperial-beach', 'Imperial Beach', 'Southernmost California beach with wide sand, gentle surf, and annual sand castle competition', 'Imperial Beach is San Diego County''s southernmost beach, offering wide sandy shores and gentle waves perfect for families. The beach is known for its annual U.S. Open Sandcastle Competition and excellent bird watching opportunities at the nearby Tijuana Estuary. The area provides a more relaxed, less crowded alternative to northern San Diego beaches.', 'https://www.imperialbeach.gov/247/Pier-Beach', 'Imperial Beach, CA 91932', 'Imperial Beach', 'San Diego', '91932', ST_GeomFromText('SRID=4326;POINT(-117.1132 32.5836)'), true, 4.4, 5230, ARRAY['https://images.unsplash.com/photo-1505228395891-9a51e7e86bf6?w=800'], ARRAY['family-friendly', 'bird-watching', 'sandcastle-competition', 'relaxed', 'southernmost-beach', 'fishing-pier'], ARRAY['parking', 'restrooms', 'showers', 'lifeguards', 'fishing-pier', 'picnic-areas', 'playground'], false, false, true, '{"beach":"24/7","pier":"24/7","park-facilities":"6:00-22:00"}'::jsonb, ARRAY['spring', 'summer', 'fall', 'winter'], 'parks', 'beaches');
