INSERT INTO locations ("slug", "name", "summary", "description", "website", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug", "subcategory_slug") VALUES ('silver-strand-state-beach', 'Silver Strand State Beach', 'Scenic narrow peninsula with both ocean and bay beaches, camping, and water sports', 'Silver Strand State Beach offers the unique experience of both Pacific Ocean and San Diego Bay beaches on a narrow strip of land. The park features camping facilities, calm bay waters perfect for swimming and kayaking, and ocean waves ideal for surfing. The area connects Coronado to Imperial Beach and provides spectacular views of both the ocean and bay.', 'https://www.parks.ca.gov/silverstrand', '5000 Hwy 75, Coronado, CA 92118', 'Coronado', 'San Diego', '92118', ST_GeomFromText('SRID=4326;POINT(-117.1234 32.6478)'), true, 4.7, 6850, ARRAY['https://images.unsplash.com/photo-1505228395891-9a51e7e86bf6?w=800'], ARRAY['camping', 'bay-beach', 'ocean-beach', 'water-sports', 'kayaking', 'swimming', 'bird-watching'], ARRAY['camping', 'parking', 'restrooms', 'showers', 'lifeguards', 'picnic-areas', 'boat-launch'], false, false, true, '{"park":"24/7","camping":"Check-in 15:00, Check-out 12:00","day-use":"8:00-sunset"}'::jsonb, ARRAY['spring', 'summer', 'fall'], 'parks', 'beaches');
