INSERT INTO locations ("slug", "name", "summary", "description", "website", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug", "subcategory_slug") VALUES ('la-jolla-shores-park', 'La Jolla Shores Park', 'Family-friendly crescent beach with gentle waves, grassy park, and kayak rentals', 'La Jolla Shores is a wide, crescent-shaped beach with gentle waves perfect for families and swimming. The adjacent park offers grassy areas, picnic tables, and playground equipment. The beach is popular for kayaking, stand-up paddleboarding, and scuba diving at the nearby La Jolla Ecological Reserve. Marine life viewing, including sea lions and dolphins, is common.', 'https://www.sandiego.gov/park-and-recreation/parks/lajolla-shores', '8300 Camino del Oro, La Jolla, CA 92037', 'San Diego', 'San Diego', '92037', ST_GeomFromText('SRID=4326;POINT(-117.2734 32.847)'), true, 4.7, 7890, ARRAY['https://images.unsplash.com/photo-1578662996442-48f60103fc96?w=800'], ARRAY['family-friendly', 'kayaking', 'scuba-diving', 'marine-life', 'gentle-waves', 'picnicking', 'playground'], ARRAY['parking', 'restrooms', 'showers', 'lifeguards', 'playground', 'picnic-areas', 'grass-park', 'rentals'], false, false, true, '{"beach":"24/7","park":"24/7","facilities":"6:00-22:00"}'::jsonb, ARRAY['spring', 'summer', 'fall', 'winter'], 'parks', 'beaches');
