INSERT INTO locations ("slug", "name", "summary", "description", "website", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug", "subcategory_slug") VALUES ('balboa-park', 'Balboa Park', 'Historic 1,200-acre urban cultural park with museums, gardens, and the San Diego Zoo', 'Balboa Park is a 1,200-acre historic urban cultural park in San Diego, California. The park contains numerous museums, theaters, gardens, shops, restaurants, and the world-famous San Diego Zoo. Many of the park''s attractions are free to explore, including beautiful gardens, walking paths, and architectural landmarks.', 'https://www.balboapark.org/', '1549 El Prado, San Diego, CA 92101', 'San Diego', 'San Diego', '92101', ST_GeomFromText('SRID=4326;POINT(-117.1596 32.7341)'), true, 4.8, 15420, ARRAY['https://images.unsplash.com/photo-1578662996442-48f60103fc96?w=800'], ARRAY['family-friendly', 'outdoors', 'museums', 'gardens', 'historic', 'cultural'], ARRAY['parking', 'restrooms', 'gift shops', 'restaurants', 'museums'], false, false, true, '{"park":"24/7","museums":"Varies by location"}'::jsonb, ARRAY['spring', 'summer', 'fall', 'winter'], 'attractions', 'parks-and-recreation');
