INSERT INTO locations ("slug", "name", "summary", "description", "website", "phone", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug", "subcategory_slug") VALUES ('torrey-pines-state-natural-reserve', 'Torrey Pines State Natural Reserve', '2,000-acre coastal wilderness reserve with rare Torrey pine trees, hiking trails, and dramatic cliff views', 'Torrey Pines State Natural Reserve is one of the wildest stretches of land on the Southern California coast, featuring rare Torrey pine trees, miles of unspoiled beaches, and stunning ocean cliffs. The reserve offers numerous hiking trails with breathtaking views of the Pacific Ocean, making it a paradise for nature lovers and hikers.', 'https://www.parks.ca.gov/torreypines', '(858) 755-2063', '12600 N Torrey Pines Rd, La Jolla, CA 92037', 'San Diego', 'San Diego', '12600', ST_GeomFromText('SRID=4326;POINT(-117.2532 32.9218)'), true, 4.9, 8750, ARRAY['https://images.unsplash.com/photo-1508672019048-805c876b67e2?w=800'], ARRAY['hiking', 'nature', 'wildlife', 'cliffs', 'beaches', 'photography', 'rare-trees'], ARRAY['parking', 'restrooms', 'visitor center', 'hiking trails', 'beach access'], false, false, true, '{"reserve":"Sunrise to sunset","visitor_center":"9:00-18:00"}'::jsonb, ARRAY['spring', 'summer', 'fall', 'winter'], 'parks', 'parks-and-recreation');
