INSERT INTO locations ("slug", "name", "summary", "description", "website", "phone", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug", "subcategory_slug") VALUES ('sunset-cliffs-natural-park', 'Sunset Cliffs Natural Park', '68-acre coastal park with dramatic sunset views, rugged cliffs, and ocean vistas', 'Sunset Cliffs Natural Park offers spectacular sunset views over the Pacific Ocean with dramatic coastal cliffs and sea caves. The park features walking paths, scenic viewpoints, and natural rock formations. It''s one of San Diego''s most photographed locations, especially during golden hour when the cliffs glow with sunset colors.', 'https://www.sandiego.gov/park-and-recreation/parks/sunset-cliffs', '(619) 221-8899', '1253 Sunset Cliffs Blvd, San Diego, CA 92107', 'San Diego', 'San Diego', '92107', ST_GeomFromText('SRID=4326;POINT(-117.2512 32.7514)'), true, 4.7, 6820, ARRAY['https://images.unsplash.com/photo-1578873292081-1f8b5b5f1e6e?w=800'], ARRAY['sunset', 'cliffs', 'ocean-views', 'photography', 'romantic', 'natural-beauty'], ARRAY['parking', 'walking paths', 'scenic viewpoints'], false, false, true, '{"park":"24/7","best_viewing":"1 hour before sunset"}'::jsonb, ARRAY['spring', 'summer', 'fall', 'winter'], 'parks', 'parks-and-recreation');
