INSERT INTO locations ("slug", "name", "summary", "description", "website", "phone", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug") VALUES ('old-town-san-diego-state-historic-park', 'Old Town San Diego State Historic Park', 'Historic park recreating San Diego life in the 1820s with original adobe buildings and period demonstrations', 'Old Town San Diego State Historic Park preserves and recreates San Diego''s early Mexican and American period. The park features historic adobe buildings, museums, restaurants, and shops. Visitors can enjoy free walking tours, watch blacksmith demonstrations, and experience California''s early history. The park comes alive with colorful fiestas and cultural events throughout the year.', 'https://www.parks.ca.gov/oldtownsandiego', '(619) 220-5422', '4002 Wallace St, San Diego, CA 92110', 'San Diego', 'San Diego', '92110', ST_GeomFromText('SRID=4326;POINT(-117.1968 32.7543)'), true, 4.6, 12450, ARRAY['https://images.unsplash.com/photo-1578662996442-48f60103fc96?w=800'], ARRAY['history', 'mexican-heritage', 'museums', 'culture', 'family-friendly', 'shopping', 'restaurants'], ARRAY['parking', 'restrooms', 'gift shops', 'restaurants', 'museums', 'walking tours'], false, false, true, '{"park":"24/7","buildings":"10:00-17:00","restaurants":"Varies"}'::jsonb, ARRAY['spring', 'summer', 'fall', 'winter'], 'attractions');
