INSERT INTO locations ("slug", "name", "summary", "description", "website", "phone", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug") VALUES ('seaport-village', 'Seaport Village', 'Waterfront shopping and dining area with street performers, art galleries, and harbor views', 'Seaport Village is a 14-acre waterfront shopping, dining, and entertainment complex along San Diego Bay. While shopping and dining cost money, visitors can enjoy free strolling along the waterfront, watch street performers, browse window displays, and enjoy beautiful harbor views. The area features historic ships, art installations, and regular free events.', 'https://www.seaportvillage.com/', '(619) 235-4014', '849 W Harbor Dr, San Diego, CA 92101', 'San Diego', 'San Diego', '92101', ST_GeomFromText('SRID=4326;POINT(-117.1758 32.7144)'), true, 4.4, 9320, ARRAY['https://images.unsplash.com/photo-1578662996442-48f60103fc96?w=800'], ARRAY['waterfront', 'shopping', 'dining', 'entertainment', 'street-performers', 'harbor-views', 'family-friendly'], ARRAY['parking', 'restrooms', 'waterfront access', 'public art'], false, false, true, '{"area":"24/7","shops":"10:00-20:00 (varies by store)","restaurants":"Varies"}'::jsonb, ARRAY['spring', 'summer', 'fall', 'winter'], 'shopping');
