INSERT INTO locations ("slug", "name", "summary", "description", "website", "phone", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug", "subcategory_slug") VALUES ('gaslamp-quarter', 'Gaslamp Quarter', 'Historic Victorian-era district with 16 blocks of dining, shopping, and entertainment venues', 'The Gaslamp Quarter is a 16-block historic neighborhood in downtown San Diego, known for its Victorian architecture, vibrant nightlife, and diverse dining scene. While restaurants and clubs charge admission, the area is free to explore on foot. Visitors can admire the historic architecture, enjoy street performances, and soak in the lively atmosphere of this National Historic District.', 'https://www.gaslamp.org/', '(619) 233-5227', '5th Ave & Island Ave, San Diego, CA 92101', 'San Diego', 'San Diego', '92101', ST_GeomFromText('SRID=4326;POINT(-117.1619 32.7105)'), true, 4.5, 7850, ARRAY['https://images.unsplash.com/photo-1578662996442-48f60103fc96?w=800'], ARRAY['historic', 'architecture', 'nightlife', 'dining', 'shopping', 'entertainment', 'victorian'], ARRAY['parking', 'restrooms', 'historic-architecture', 'street-performers'], false, false, true, '{"area":"24/7","businesses":"Varies by establishment"}'::jsonb, ARRAY['spring', 'summer', 'fall', 'winter'], 'attractions', 'attractions');
