INSERT INTO locations ("slug", "name", "summary", "description", "website", "phone", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug", "subcategory_slug") VALUES ('mission-bay-park', 'Mission Bay Park', '4,600-acre aquatic park with beaches, bike paths, and water sports activities', 'Mission Bay Park is a massive 4,600-acre aquatic park offering 27 miles of shoreline, including numerous beaches, picnic areas, and recreational facilities. The park is perfect for biking, walking, jogging, and water sports. Visitors can enjoy free beach access, playgrounds, and beautiful bay views. The calm waters make it ideal for families and water sports enthusiasts.', 'https://www.sandiego.gov/park-and-recreation/parks/mission-bay', '(619) 694-3049', '2688 E Mission Bay Dr, San Diego, CA 92109', 'San Diego', 'San Diego', '92109', ST_GeomFromText('SRID=4326;POINT(-117.2134 32.7795)'), true, 4.6, 5890, ARRAY['https://images.unsplash.com/photo-1578662996442-48f60103fc96?w=800'], ARRAY['beaches', 'water-sports', 'biking', 'picnicking', 'family-friendly', 'recreation', 'bay-views'], ARRAY['parking', 'restrooms', 'playgrounds', 'beach access', 'bike paths', 'picnic areas'], false, false, true, '{"park":"24/7","facilities":"Varies by location"}'::jsonb, ARRAY['spring', 'summer', 'fall', 'winter'], 'parks', 'parks-and-recreation');
