INSERT INTO locations ("slug", "name", "summary", "description", "website", "address", "city", "region", "postal_code", "coordinates", "price_level", "is_free", "cost_estimate", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug", "subcategory_slug") VALUES ('san-diego-zoo', 'San Diego Zoo', 'World-famous zoo with 12,000 animals in naturalistic habitats, conservation leader', 'The San Diego Zoo is a world-renowned zoo housing over 12,000 animals of more than 650 species and subspecies. Known for its pioneering approach to naturalistic animal enclosures and conservation efforts, the zoo offers guided tours, special experiences, and educational programs. It''s one of the few zoos in the world to house giant pandas and is internationally recognized for its breeding programs.', 'https://zoo.sandiegozoo.org/', '2920 Zoo Dr, San Diego, CA 92101', 'San Diego', 'San Diego', '92101', ST_GeomFromText('SRID=4326;POINT(-117.149 32.7353)'), 4, false, 'Adults: $62-75, Children: $52-65, Seniors: $52-65', 4.8, 45890, ARRAY['https://images.unsplash.com/photo-1583337134317-4bf93c5fee04?w=800'], ARRAY['animals', 'conservation', 'family-friendly', 'pandas', 'world-class', 'educational'], ARRAY['parking', 'restrooms', 'restaurants', 'gift shops', 'transportation', 'guided-tours'], true, false, true, '{"zoo":"9:00-18:00 (daily, hours vary by season)","special_experiences":"Varies by program"}'::jsonb, ARRAY['spring', 'summer', 'fall', 'winter'], 'attractions', 'attractions');
