INSERT INTO locations ("slug", "name", "summary", "description", "website", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug", "subcategory_slug") VALUES ('griffith-park', 'Griffith Park', '4,210-acre urban park with hiking trails, Griffith Observatory, and Hollywood Sign views', 'Griffith Park is one of the largest urban parks in North America, offering extensive hiking trails, picnic areas, and stunning views of Los Angeles and the iconic Hollywood Sign. While the Griffith Observatory and planetarium shows require tickets, the park grounds, hiking trails, and many viewpoints are completely free to explore.', 'https://www.laparks.org/griffithpark', '4730 Crystal Springs Dr, Los Angeles, CA 90027', 'Los Angeles', 'Los Angeles', '90027', ST_GeomFromText('SRID=4326;POINT(-118.2935 34.1365)'), true, 4.8, 25680, ARRAY['https://images.unsplash.com/photo-1520467790875-79e45456c6c0?w=800'], ARRAY['hiking', 'hollywood-sign', 'city-views', 'family-friendly', 'outdoors', 'picnicking', 'nature'], ARRAY['parking', 'restrooms', 'hiking trails', 'picnic areas', 'playgrounds', 'horseback riding'], false, false, true, '{"park":"24/7","observatory_exterior":"24/7","facilities":"Varies by location"}'::jsonb, ARRAY['spring', 'summer', 'fall', 'winter'], 'parks', 'parks-and-recreation');
