INSERT INTO locations ("slug", "name", "summary", "description", "website", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug", "subcategory_slug") VALUES ('the-getty-center', 'The Getty Center', 'World-class art museum with stunning architecture, gardens, and panoramic city views', 'The Getty Center is a world-renowned art museum featuring European paintings, drawings, sculptures, decorative arts, and photographs from the Middle Ages to the present. The complex is famous for its stunning architecture, beautiful gardens, and panoramic views of Los Angeles. While parking costs money, admission to the museum and all exhibitions is completely free.', 'https://www.getty.edu/visit/center/', '1200 Getty Center Dr, Los Angeles, CA 90049', 'Los Angeles', 'Los Angeles', '90049', ST_GeomFromText('SRID=4326;POINT(-118.4747 34.0775)'), true, 4.7, 18950, ARRAY['https://images.unsplash.com/photo-1594736797933-d0acc2401915?w=800'], ARRAY['art', 'architecture', 'gardens', 'city-views', 'family-friendly', 'photography', 'culture'], ARRAY['parking', 'restrooms', 'restaurants', 'gift shops', 'gardens', 'audio-guides'], false, false, true, '{"museum":"Tuesday-Friday: 10:00-17:00, Saturday-Sunday: 10:00-17:00","gardens":"24/7 access","closed":"Mondays"}'::jsonb, ARRAY['spring', 'summer', 'fall', 'winter'], 'attractions', 'culture-and-arts');
