INSERT INTO locations ("slug", "name", "summary", "description", "website", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug", "subcategory_slug") VALUES ('hollywood-walk-of-fame', 'Hollywood Walk of Fame', 'Iconic sidewalk with celebrity stars, historic theaters, and Hollywood glamour', 'The Hollywood Walk of Fame is a world-famous attraction featuring more than 2,600 brass stars embedded in the sidewalks along Hollywood Boulevard and Vine Street. The walk celebrates achievements in the entertainment industry, with stars honoring actors, musicians, directors, and other celebrities. The surrounding area includes historic theaters like the TCL Chinese Theatre and the Dolby Theatre.', 'https://www.walkoffame.com/', 'Hollywood Blvd & Vine St, Los Angeles, CA 90028', 'Los Angeles', 'Los Angeles', '90028', ST_GeomFromText('SRID=4326;POINT(-118.3269 34.1018)'), true, 4.4, 32480, ARRAY['https://images.unsplash.com/photo-1578662996442-48f60103fc96?w=800'], ARRAY['hollywood', 'celebrities', 'entertainment', 'historic-theaters', 'photography', 'tourist-attraction'], ARRAY['parking', 'restrooms', 'restaurants', 'shops', 'tourist-information'], false, false, true, '{"walk":"24/7","ceremonies":"Varies by event","theaters":"Varies by venue"}'::jsonb, ARRAY['spring', 'summer', 'fall', 'winter'], 'attractions', 'attractions');
-- Source: unknown/unknown

INSERT INTO locations ("slug", "name", "summary", "description", "website", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug", "subcategory_slug") VALUES ('santa-monica-pier', 'Santa Monica Pier', 'Historic pier with carnival rides, Pacific Park amusement area, and beachfront views', 'The Santa Monica Pier is a historic landmark dating back to 1909, featuring the Pacific Park amusement area with rides like the solar-powered Pacific Wheel Ferris wheel and West Coaster roller coaster. While individual rides cost money, walking on the pier, enjoying ocean views, and watching the sunset are completely free. The pier offers classic beach town atmosphere with street performers, fishing, and dining options.', 'https://www.santamonicapier.org/', '200 Santa Monica Pier, Santa Monica, CA 90401', 'Santa Monica', 'Los Angeles', '90401', ST_GeomFromText('SRID=4326;POINT(-118.4998 34.0089)'), true, 4.5, 19458, ARRAY['https://images.unsplash.com/photo-1505228395891-9a51e7e86bf6?w=800'], ARRAY['beach', 'pier', 'amusement-rides', 'sunset', 'family-friendly', 'ocean-views', 'historic'], ARRAY['parking', 'restrooms', 'restaurants', 'shops', 'fishing', 'playground'], false, false, true, '{"pier":"24/7","rides":"Monday-Friday: 12:00-20:00, Saturday-Sunday: 11:00-20:00","seasonal_hours":"Extended summer hours"}'::jsonb, ARRAY['spring', 'summer', 'fall', 'winter'], 'attractions', 'outdoor-activities');
