INSERT INTO locations ("slug", "name", "summary", "description", "website", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug", "subcategory_slug") VALUES ('venice-beach-boardwalk', 'Venice Beach Boardwalk', 'Eclectic boardwalk with street performers, artists, skate park, and Venice Canals', 'The Venice Beach Boardwalk is one of LA''s most iconic and colorful destinations, featuring a diverse array of street performers, artists, vendors, and attractions. The area includes the famous Venice Skate Park, outdoor basketball courts, bodybuilding areas, and numerous shops and cafes. The adjacent Venice Canals offer a peaceful contrast with beautiful residential waterways. It''s a celebration of LA''s bohemian beach culture.', 'https://www.laparks.org/venice/', '1800 Ocean Front Walk, Los Angeles, CA 90291', 'Los Angeles', 'Los Angeles', '90291', ST_GeomFromText('SRID=4326;POINT(-118.4695 33.985)'), true, 4.6, 21890, ARRAY['https://images.unsplash.com/photo-1578662996442-48f60103fc96?w=800'], ARRAY['street-performers', 'skateboarding', 'beach-culture', 'bohemian', 'artists', 'canals', 'basketball'], ARRAY['parking', 'restrooms', 'skate-park', 'basketball-courts', 'outdoor-gym', 'shops'], false, false, true, '{"boardwalk":"24/7","facilities":"Varies by location","skate_park":"8:00-sunset"}'::jsonb, ARRAY['spring', 'summer', 'fall', 'winter'], 'attractions', 'outdoor-activities');
