INSERT INTO locations ("slug", "name", "summary", "description", "website", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug", "subcategory_slug") VALUES ('runyon-canyon-park', 'Runyon Canyon Park', 'Popular hiking trail with Hollywood Sign views and celebrity sightings', 'Runyon Canyon Park is one of LA''s most famous hiking spots, offering scenic trails with panoramic views of Los Angeles and the Hollywood Sign. The park attracts fitness enthusiasts, dog walkers, and celebrities seeking exercise. Multiple trail options range from easy walks to challenging hikes, making it accessible to various fitness levels. The park is known for its social scene and stunning city views.', 'https://www.laparks.org/runyon-canyon-park', '2000 N Fuller Ave, Los Angeles, CA 90046', 'Los Angeles', 'Los Angeles', '90046', ST_GeomFromText('SRID=4326;POINT(-118.3448 34.1269)'), true, 4.4, 8750, ARRAY['https://images.unsplash.com/photo-1578662996442-48f60103fc96?w=800'], ARRAY['hiking', 'city-views', 'hollywood-sign', 'dog-friendly', 'fitness', 'celebrity-sightings'], ARRAY['parking', 'hiking trails', 'water fountains', 'bag dispensers', 'multiple entrances'], false, false, true, '{"park":"24/7","gates":"6:30-dusk","best_hiking":"Early morning or late afternoon"}'::jsonb, ARRAY['spring', 'summer', 'fall', 'winter'], 'parks', 'parks-and-recreation');
