INSERT INTO locations ("slug", "name", "summary", "description", "website", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug") VALUES ('olvera-street', 'Olvera Street', 'Birthplace of Los Angeles with historic Mexican marketplace and cultural attractions', 'Olvera Street is known as the birthplace of Los Angeles, offering a vibrant taste of old Mexico with historic buildings, traditional restaurants, and colorful shops. The street features the Avila Adobe, the oldest standing residence in Los Angeles, along with museums, cultural performances, and authentic Mexican cuisine. It''s a free outdoor museum celebrating LA''s Mexican heritage and founding.', 'https://olvera-street.com/', '845 N Alameda St, Los Angeles, CA 90012', 'Los Angeles', 'Los Angeles', '90012', ST_GeomFromText('SRID=4326;POINT(-118.2369 34.0626)'), true, 4.4, 6580, ARRAY['https://images.unsplash.com/photo-1578662996442-48f60103fc96?w=800'], ARRAY['history', 'mexican-heritage', 'culture', 'museums', 'shopping', 'traditional-food', 'founding-of-LA'], ARRAY['parking', 'restrooms', 'museums', 'restaurants', 'shops', 'cultural-performances'], false, false, true, '{"street":"10:00-19:00 (daily)","museums":"10:00-16:00 (Wednesday-Sunday)","restaurants":"Varies by establishment"}'::jsonb, ARRAY['spring', 'summer', 'fall', 'winter'], 'attractions');
