INSERT INTO locations ("slug", "name", "summary", "description", "website", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug", "subcategory_slug") VALUES ('the-grove', 'The Grove', 'Outdoor shopping center with beautiful landscaping, fountain shows, and free trolley', 'The Grove is an upscale outdoor shopping and entertainment center featuring beautiful architecture, landscaping, and a choreographed fountain show. While shopping and dining cost money, visitors can enjoy free strolling through the property, watching the fountain shows, riding the free trolley to The Original Farmers Market, and admiring the ambiance. The center features a dancing water fountain synchronized to music and seasonal decorations.', 'https://www.thegrovela.com/', '189 The Grove Dr, Los Angeles, CA 90036', 'Los Angeles', 'Los Angeles', '90036', ST_GeomFromText('SRID=4326;POINT(-118.357 34.0481)'), true, 4.6, 12450, ARRAY['https://images.unsplash.com/photo-1578662996442-48f60103fc96?w=800'], ARRAY['shopping', 'outdoor-mall', 'fountain-shows', 'family-friendly', 'dining', 'entertainment'], ARRAY['parking', 'restrooms', 'free-trolley', 'fountain-shows', 'playground'], false, false, true, '{"center":"10:00-21:00 (Monday-Saturday), 11:00-19:00 (Sunday)","fountain_shows":"Every hour during operating hours","trolley":"During center hours"}'::jsonb, ARRAY['spring', 'summer', 'fall', 'winter'], 'shopping', 'shopping');
