INSERT INTO locations ("slug", "name", "summary", "description", "website", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug") VALUES ('mission-inn-festival-of-lights', 'Mission Inn Festival of Lights', 'Historic hotel with spectacular Christmas light display and holiday festivities', 'The Mission Inn Festival of Lights is a spectacular holiday tradition featuring over 5 million lights decorating the historic Mission Inn Hotel. While the hotel itself requires paid access, the outdoor light display and surrounding festivities are completely free to enjoy from the street. The event includes live entertainment, holiday vendors, and beautiful holiday decorations throughout downtown Riverside.', 'https://www.missioninn.com/festival-of-lights', '3649 Mission Inn Ave, Riverside, CA 92501', 'Riverside', 'Inland Empire', '92501', ST_GeomFromText('SRID=4326;POINT(-117.3769 33.9832)'), true, 4.8, 12480, ARRAY['https://images.unsplash.com/photo-1578662996442-48f60103fc96?w=800'], ARRAY['holiday', 'christmas', 'lights', 'historic-hotel', 'family-tradition', 'festivals'], ARRAY['parking', 'restaurants', 'shopping', 'entertainment', 'historic-architecture'], false, false, true, '{"light_display":"Daily from late November through December, 17:00-24:00","seasonal":"Holiday season only (November-January)"}'::jsonb, ARRAY['winter'], 'attractions');
