INSERT INTO locations ("slug", "name", "summary", "description", "website", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug") VALUES ('march-field-air-museum', 'March Field Air Museum', 'Aviation museum with historic aircraft and free outdoor aircraft displays', 'March Field Air Museum features an impressive collection of historic aircraft and aviation artifacts, with many aircraft displayed outdoors for free viewing. The indoor museum has an admission fee, but the outdoor aircraft collection, including helicopters, fighter jets, and bombers from various eras, can be viewed completely free. The museum is located at the historic March Air Reserve Base.', 'https://www.marchfield.org/', '22550 Van Buren Blvd, Riverside, CA 92518', 'Riverside', 'Inland Empire', '22550', ST_GeomFromText('SRID=4326;POINT(-117.4256 33.8769)'), true, 4.6, 6890, ARRAY['https://images.unsplash.com/photo-1578662996442-48f60103fc96?w=800'], ARRAY['aviation', 'military', 'aircraft', 'history', 'family-friendly', 'outdoor-exhibits'], ARRAY['parking', 'gift shop', 'restrooms', 'picnic areas'], false, false, true, '{"outdoor_displays":"24/7 visibility from perimeter","museum":"10:00-17:00 (Tuesday-Sunday, paid admission)","closed":"Mondays"}'::jsonb, ARRAY['spring', 'summer', 'fall', 'winter'], 'attractions');
