INSERT INTO locations ("slug", "name", "summary", "description", "website", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug", "subcategory_slug") VALUES ('pioneer-park', 'Pioneer Park', 'Historic park with original Temecula buildings, museums, and Old West charm', 'Pioneer Park in Temecula preserves the town''s pioneer heritage with historic buildings, including the original Temecula jail, schoolhouse, and various pioneer-era structures. The park offers free outdoor exploration of historic buildings, picnic areas, and beautiful views of the surrounding countryside. It''s a peaceful step back into Southern California''s Old West history.', 'https://www.temeculaca.gov/ThingsToDo/PioneerPark', '31985 Moreno Rd, Temecula, CA 92592', 'Temecula', 'Inland Empire', '31985', ST_GeomFromText('SRID=4326;POINT(-117.1474 33.4968)'), true, 4.5, 3240, ARRAY['https://images.unsplash.com/photo-1578662996442-48f60103fc96?w=800'], ARRAY['history', 'pioneer-era', 'old-west', 'picnicking', 'family-friendly', 'historic-buildings'], ARRAY['parking', 'restrooms', 'picnic areas', 'walking paths', 'historic-structures'], false, false, true, '{"park":"24/7","building_viewing":"Outdoor viewing available anytime","picnic_areas":"24/7"}'::jsonb, ARRAY['spring', 'summer', 'fall', 'winter'], 'parks', 'parks-and-recreation');
