INSERT INTO locations ("slug", "name", "summary", "description", "website", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug") VALUES ('big-bear-discovery-center', 'Big Bear Discovery Center', 'Mountain nature center with forest information, trails, and wildlife education', 'The Big Bear Discovery Center serves as the gateway to the San Bernardino National Forest, offering free outdoor exhibits, trail information, and educational displays about local wildlife and forest ecology. While some programs and facility rentals have fees, the center itself, outdoor exhibits, and access to trail heads are completely free. It''s an excellent starting point for exploring Big Bear Lake''s natural beauty.', 'https://www.disbigbear.com/', '40971 North Shore Dr, Fawnskin, CA 92333', 'Fawnskin', 'Inland Empire', '40971', ST_GeomFromText('SRID=4326;POINT(-116.8983 34.2712)'), true, 4.4, 4580, ARRAY['https://images.unsplash.com/photo-1578662996442-48f60103fc96?w=800'], ARRAY['nature', 'wildlife', 'hiking', 'forests', 'mountains', 'family-friendly', 'education'], ARRAY['parking', 'restrooms', 'information center', 'trail access', 'picnic areas'], false, false, true, '{"center":"8:00-17:00 (daily)","outdoor_exhibits":"24/7 access","trails":"Dawn to dusk"}'::jsonb, ARRAY['spring', 'summer', 'fall', 'winter'], 'parks');
