INSERT INTO locations ("slug", "name", "summary", "description", "website", "address", "city", "region", "postal_code", "coordinates", "is_free", "rating", "review_count", "photos", "tags", "amenities", "is_premium", "is_featured", "is_published", "hours", "seasonality", "category_slug") VALUES ('lake-perris-state-recreation-area', 'Lake Perris State Recreation Area', 'Large reservoir with beaches, hiking trails, fishing, and outdoor recreation', 'Lake Perris State Recreation Area offers diverse outdoor activities around a large reservoir in the heart of the Inland Empire. While day-use parking has fees, the lake perimeter can be accessed for free viewing from certain areas, and the surrounding hills provide excellent hiking opportunities. The park features sandy beaches, fishing areas, picnic spots, and beautiful mountain views.', 'https://www.parks.ca.gov/?page_id=656', '18700 Lake Perris Dr, Perris, CA 92571', 'Perris', 'Inland Empire', '18700', ST_GeomFromText('SRID=4326;POINT(-117.2479 33.7901)'), true, 4.5, 7890, ARRAY['https://images.unsplash.com/photo-1578662996442-48f60103fc96?w=800'], ARRAY['lake', 'fishing', 'hiking', 'picnicking', 'beaches', 'outdoor-recreation', 'water-sports'], ARRAY['parking', 'restrooms', 'picnic areas', 'hiking trails', 'beach access', 'fishing'], false, false, true, '{"park":"24/7 access to perimeter areas","facilities":"Varies by season and facility type","day_use":"Sunrise to sunset"}'::jsonb, ARRAY['spring', 'summer', 'fall', 'winter'], 'parks');
